import anthropic

# Anthropic extended thinking: the model reasons privately, then responds.
# Reasoning tokens are billed separately and do not appear in output by default.
client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-5",  # Supports extended thinking
    max_tokens=8000,
    thinking={
        "type": "enabled",
        "budget_tokens": 5000,   # Max tokens for private reasoning
    },
    messages=[{
        "role": "user",
        "content": (
            "A farmer has 17 sheep. All but 9 die. How many sheep are left? "
            "Show your reasoning."
        ),
    }],
)

for block in response.content:
    if block.type == "thinking":
        print(f"[Private reasoning] {block.thinking[:200]}...")
    elif block.type == "text":
        print(f"[Answer] {block.text}")
